import{c as p,a7 as e,y as i,B as r}from"./chunks/framework.3cjvm90C.js";const c=JSON.parse('{"title":"The RDD","description":"Spark RDD 弹性分布式数据集的核心概念与操作","frontmatter":{"title":"The RDD","description":"Spark RDD 弹性分布式数据集的核心概念与操作"},"headers":[],"relativePath":"mlwiki/Spark/spark_rdd.md","filePath":"mlwiki/Spark/spark_rdd.md","lastUpdated":1782456021000}'),s={name:"mlwiki/Spark/spark_rdd.md"};function l(t,a,n,d,k,h){return e(),i("div",null,[...a[0]||(a[0]=[r('<h2 id="the-rdd" tabindex="-1">The RDD <a class="header-anchor" href="#the-rdd" aria-label="Permalink to “The RDD”">​</a></h2><p>Spark 是用于大规模数据处理的集群计算框架。 Spark 为统一计算引擎提供了 3 种语言（Java，Scala 和 Python）的一组库。 这个定义实际上是什么意思？</p><p>统一：借助 Spark，无需将多个 API 或系统中的应用程序组合在一起。 Spark 为您提供了足够的内置 API 来完成工作</p><p>计算引擎：Spark 处理来自各种文件系统的数据加载并在其上运行计算，但不会永久存储任何数据本身。 Spark 完全在内存中运行-允许无与伦比的性能和速度</p><p>库：Spark 由为数据科学任务而构建的一系列库组成。 Spark 包括用于 SQL（SparkSQL），机器学习（MLlib），流处理（Spark 流和结构化流）和图分析（GraphX）的库</p><h3 id="spark-application" tabindex="-1">Spark Application <a class="header-anchor" href="#spark-application" aria-label="Permalink to “Spark Application”">​</a></h3><p>每个 Spark Application 程序都包含一个驱动程序和一组分布式工作进程（执行程序）。</p><h2 id="spark-driver" tabindex="-1">Spark Driver <a class="header-anchor" href="#spark-driver" aria-label="Permalink to “Spark Driver”">​</a></h2><p>驱动程序运行我们应用程序的 main（）方法，并在其中创建 SparkContext。 Spark 驱动程序具有以下职责：</p><ul><li>在集群中的节点上或客户端上运行，并通过集群管理器调度作业执行</li><li>响应用户的程序或输入</li><li>分析，安排和分配各个部门的工作</li><li>存储有关正在运行的应用程序的元数据，并在 WebUI 中方便地公开它</li></ul><h3 id="spark-executors" tabindex="-1">Spark Executors <a class="header-anchor" href="#spark-executors" aria-label="Permalink to “Spark Executors”">​</a></h3><p>Executors 是负责执行任务的分布式过程。每个 Spark 应用程序都有其自己的执行程序集，这些执行程序在单个 Spark 应用程序的生命周期内保持有效。</p><ul><li>Executor 执行 Spark 作业的所有数据处理</li><li>将结果存储在内存中，仅在驱动程序有特别指示时才保留在磁盘上</li><li>完成结果后，将结果返回给驱动程序</li><li>每个节点可以具有从每个节点 1 个执行程序到每个核心 1 个执行程序的任意位置</li></ul><p><img src="https://hackernoon.com/hn-images/1*GZG2aogNS8Jg14jOM2rjmQ.png" alt="img"></p><h3 id="spark-application-工作流程当您将作业提交给-spark-进行处理时-幕后还有很多事情要做。" tabindex="-1">Spark Application 工作流程当您将作业提交给 Spark 进行处理时，幕后还有很多事情要做。 <a class="header-anchor" href="#spark-application-工作流程当您将作业提交给-spark-进行处理时-幕后还有很多事情要做。" aria-label="Permalink to “Spark Application 工作流程当您将作业提交给 Spark 进行处理时，幕后还有很多事情要做。”">​</a></h3><p>我们的独立应用程序启动，并初始化其 SparkContext。 只有拥有 SparkContext 之后，才能将应用程序称为驱动程序</p><ul><li>我们的驱动程序要求集群管理器提供启动其执行程序的资源</li><li>集群管理器启动执行程序</li><li>我们的驱动程序运行我们的实际 Spark 代码</li><li>执行程序运行任务并将其结果发送回驱动程序</li><li>SparkContext 已停止并且所有执行程序都已关闭，将资源返回给集群</li></ul><h3 id="spark-架构概述" tabindex="-1">Spark 架构概述 <a class="header-anchor" href="#spark-架构概述" aria-label="Permalink to “Spark 架构概述”">​</a></h3><p>Spark 具有定义明确的分层架构，其基于两个主要抽象的组件具有松散耦合：</p><ul><li>弹性分布式数据集（RDD）</li><li>有向无环图（DAG）</li></ul><p><img src="https://miro.medium.com/max/60/1*Ck-GUoBRx7b8rxrgQlNEGQ.png?q=20" alt="img"></p><p><img src="https://miro.medium.com/max/1312/1*Ck-GUoBRx7b8rxrgQlNEGQ.png" alt="img"></p><p>From PySpark-Pictures by Jeffrey Thompson.</p><h3 id="弹性分布式数据集" tabindex="-1">弹性分布式数据集 <a class="header-anchor" href="#弹性分布式数据集" aria-label="Permalink to “弹性分布式数据集”">​</a></h3><p>RDD 本质上是 Spark 的构建块：一切都由它们组成。 甚至 Sparks 更高级别的 API（DataFrame，Dataset）也由 RDD 组成。</p><p>弹性：由于 Spark 在机器集群上运行，因此硬件故障造成的数据丢失是一个非常现实的问题，因此 RDD 具有容错能力，并且在发生故障时可以自行重建.</p><p>分布式：单个 RDD 存储在群集中的一系列不同节点上，不属于单个源（也不属于单个故障点）。 这样我们的集群可以并行地在 RDD 上运行</p><p>数据集：值的集合-您应该已经知道的这个值</p><p>Apache Spark 的最为核心的抽象是弹性分布式数据集（RDD）。 RDD 是可以并行操作的元素的容错集合。您可以并行化驱动程序中的现有集合，或引用外部存储系统（如共享文件系统、HDFS、HBase 或提供 Hadoop InputFormat 的任何数据源）中的数据集来创建它们。</p><p>我们在 Spark 中使用的所有数据都将存储在某种形式的 RDD 中，因此必须完全理解它们。</p><p>Spark 提供了许多在 RDD 之上构建的“高级” API，这些 API 旨在抽象化复杂性，即 DataFrame 和 Dataset。 Scala 和 Python 中的 Spark-Submit 和 Spark-Shell 着重于读取-评估-打印循环（REPL），是针对数据科学家的，他们经常希望对数据集进行重复分析。 仍然需要理解 RDD，因为它是 Spark 中所有数据的基础结构。</p><p>RDD 在口语上等同于：“分布式数据结构”。 <code>JavaRDD&lt;String&gt;</code>本质上只是一个 List <code>String</code>，分布在我们集群中的每个节点之间，每个节点都获得 List 的几个不同块。 使用 Spark，我们需要始终在分布式环境中进行思考。</p><p>RDD 通过将其数据分成一系列分区存储在每个执行程序节点上来工作。 然后，每个节点将仅在其自己的分区上执行其工作。 这就是 Spark 如此强大的原因：如果 Executor 死亡或任务失败，Spark 可以从原始源中重建所需的分区，然后重新提交任务以完成任务。</p><p><img src="https://hackernoon.com/hn-images/1*7aXGUcCy3qHD3U66COrTTA.png" alt="img"></p><p>Spark RDD partitioned amongst executors</p><h3 id="rdd-操作" tabindex="-1">RDD 操作 <a class="header-anchor" href="#rdd-操作" aria-label="Permalink to “RDD 操作”">​</a></h3><p>RDD 是不可变的，这意味着一旦创建它们，就不能以任何方式对其进行更改，而只能对其进行转换。转换 RDD 的概念是 Spark 的核心，可以将 Spark Jobs 视为这些步骤的任意组合：</p><ul><li><p>将数据加载到 RDD 中</p></li><li><p>转换 RDD</p></li><li><p>在 RDD 上执行操作</p></li></ul><p>实际上，我编写的每一个 Spark 作业都完全由这些类型的任务组成，并带有香草味的 Java 语言。</p><p>Spark 定义了一组用于处理 RDD 的 API，可以将其分为两大类：转换和操作。</p><ul><li><p>转换会从现有的 RDD 创建一个新的 RDD。</p></li><li><p>操作在其 RDD 上运行计算后，会将一个或多个值返回给驱动程序。</p></li></ul><p>例如，地图函数 weatherData.map（）是一种转换，它通过函数传递 RDD 的每个元素。</p><p>Reduce 是一个 RDD 操作，它使用某些函数来聚合 RDD 的所有元素，并将最终结果返回给驱动程序。</p><h3 id="懒惰评估" tabindex="-1">懒惰评估 <a class="header-anchor" href="#懒惰评估" aria-label="Permalink to “懒惰评估”">​</a></h3><p>“我选择一个懒惰的人做艰苦的工作。因为一个懒惰的人会找到一种简单的方法来做到这一点。 - 比尔盖茨”</p><p>Spark 中的所有转换都是惰性的。这意味着，当我们告诉 Spark 通过现有 RDD 的转换来创建 RDD 时，直到对该数据集或其子对象执行特定操作之前，它不会生成该数据集。然后，Spark 将执行转换以及触发转换的操作。这使 Spark 可以更有效地运行。</p><p>让我们重新检查之前的 Spark 示例中的函数声明，以识别哪些函数是动作，哪些是转换：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>16：JavaRDD&amp;lt;String&amp;gt; weatherData = sc.textFile（inputPath）;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>第 16 行既不是动作也不是变换。它是 sc（我们的 JavaSparkContext）的功能。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>17：JavaPairRDD &lt;String，Integer&gt; tempsByCountry = weatherData.mapToPair（新函数..</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>第 17 行是 weatherData RDD 的转换，其中我们将 weatherData 的每一行映射到由（City，Temperature）组成的一对</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>26：JavaPairRDD &lt;String，Integer&gt; maxTempByCountry = tempsByCountry.reduce（新函数...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>第 26 行也是一种转换，因为我们正在遍历键值对。这是对 tempsByCountry 的一种转换，在该转换中，我们将每个城市的温度降低到最高记录温度。</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>31：maxTempByCountry.saveAsHadoopFile（destPath，String.class，Integer.class，TextOutputFormat.class）；</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>最后，在第 31 行，我们触发了 Spark 动作：将 RDD 保存到文件系统中。 由于 Spark 订阅了惰性执行模型，因此直到这一行 Spark 生成 weatherData，tempsByCountry 和 maxTempsByCountry 才最终保存我们的结果。</p><h3 id="有向无环图每当在-rdd-上执行操作时-spark-都会创建-dag-即无向循环的有限直接图-否则我们的工作将永远运行-。-请记住-图只不过是一系列连接的顶点和边-并且该图也没有什么不同。-dag-中的每个顶点都是-spark-函数-在-rdd-上执行某些操作-map-maptopair-reducebykey-等-。" tabindex="-1">有向无环图每当在 RDD 上执行操作时，Spark 都会创建 DAG，即无向循环的有限直接图（否则我们的工作将永远运行）。 请记住，图只不过是一系列连接的顶点和边，并且该图也没有什么不同。 DAG 中的每个顶点都是 Spark 函数，在 RDD 上执行某些操作（map，mapToPair，reduceByKey 等）。 <a class="header-anchor" href="#有向无环图每当在-rdd-上执行操作时-spark-都会创建-dag-即无向循环的有限直接图-否则我们的工作将永远运行-。-请记住-图只不过是一系列连接的顶点和边-并且该图也没有什么不同。-dag-中的每个顶点都是-spark-函数-在-rdd-上执行某些操作-map-maptopair-reducebykey-等-。" aria-label="Permalink to “有向无环图每当在 RDD 上执行操作时，Spark 都会创建 DAG，即无向循环的有限直接图（否则我们的工作将永远运行）。 请记住，图只不过是一系列连接的顶点和边，并且该图也没有什么不同。 DAG 中的每个顶点都是 Spark 函数，在 RDD 上执行某些操作（map，mapToPair，reduceByKey 等）。”">​</a></h3><p>在 MapReduce 中，DAG 由两个顶点组成：“贴图”→“缩小”。</p><p>在我们上面的 MaxTemperatureByCountry 示例中，DAG 涉及更多：</p><p>parallelize → map → mapToPair → reduce → saveAsHadoopFile</p><p>DAG 使 Spark 可以优化其执行计划并最大程度地减少改组。 我们将在以后的文章中更深入地讨论 DAG，因为它不在本 Spark 概述的范围之内。</p><h3 id="评估循环" tabindex="-1">评估循环 <a class="header-anchor" href="#评估循环" aria-label="Permalink to “评估循环”">​</a></h3><p>使用我们的新词汇，让我们重新检查我在第一部分中定义的 MapReduce 的问题，如下所述：</p><p>MapReduce 在批处理数据方面表现出色，但是在重复分析和小的反馈循环方面却落后。在计算之间重用数据的唯一方法是将其写入外部存储系统（例如 HDFS）” “在计算之间重复使用数据”？听起来像是可以对其执行多项操作的 RDD！假设我们有一个文件“ data.txt”，并且想要完成两个计算：</p><ul><li>文件中所有行的总长度</li><li>文件中最长行的长度</li></ul><p>在 MapReduce 中，每个任务将需要单独的作业或精美的 MulitpleOutputFormat 实现。只需四个简单的步骤，Spark 即可轻松实现：</p><p>1.将 data.txt 的内容加载到 RDD 中</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>JavaRDD&amp;lt;String&amp;gt;行= sc.textFile（“ data.txt”）;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>2.将“行”的每一行映射到其长度（为简洁起见使用 Lambda 函数）</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>JavaRDD&amp;lt;Integer&amp;gt; lineLengths = lines.map（s-&gt; s.length（））;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>3.解决总长度：减少 lineLengths 以找到总线长总和，在这种情况下，是 RDD 中每个元素的总和</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>int totalLength = lineLengths.reduce（（a，b）-&gt; a + b）;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>4.解决最长的长度：减小 lineLengths 以找到最大的行长</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes light-plus dark-plus" style="--shiki-light:#000000;--shiki-dark:#D4D4D4;--shiki-light-bg:#FFFFFF;--shiki-dark-bg:#1E1E1E;" tabindex="0" dir="ltr"><code><span class="line"><span>int maxLength = lineLengths.reduce（（a，b）-&gt; Math.max（a，b））;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>请注意，第 3 步和第 4 步是 RDD 动作，因此它们将结果返回到我们的 Driver 程序，在本例中为 Java int。还要记住，Spark 是懒惰的，并且拒绝执行任何工作，直到看到一个动作为止，在这种情况下，它直到第 3 步才开始任何实际的工作。</p>',74)])])}const D=p(s,[["render",l]]);export{c as __pageData,D as default};
